import 'package:injectable/injectable.dart'; import 'package:uuid/uuid.dart'; import '../model/trusted_device.dart'; import 'trusted_device_manager.dart'; @injectable class TrustedPairingService { final TrustedDeviceManager _manager; TrustedPairingService(this._manager); Future<TrustedDevice> pairDevice({required String deviceName, required String ownerUid, String? fcmToken}) async { final device = TrustedDevice(deviceId: const Uuid().v4(), deviceName: deviceName, ownerUid: ownerUid, pairedAt: DateTime.now(), fcmToken: fcmToken); await _manager.saveTrustedDevice(device); return device; } Future<void> unpairDevice(String deviceId) => _manager.removeDevice(deviceId); Future<bool> isPaired(String deviceId) => _manager.isTrusted(deviceId); }